<pre><code>impl&lt;'a&gt; DmxUsart&lt;'a&gt; {
    pub fn new&lt;T&gt;(
        peri: Peri&lt;'a, T&gt;,
        rx: Peri&lt;'a, impl RxPin&lt;T&gt;&gt;,
        tx: Peri&lt;'a, impl TxPin&lt;T&gt;&gt;,
