        tx_dma: Peri&lt;'a, impl TxDma&lt;T&gt;&gt;,
        rx_dma: Peri&lt;'a, impl RxDma&lt;T&gt;&gt;,
        de: Peri&lt;'a, impl Pin&gt;,
