    where
        T: usart::Instance,
    {
        let mut config = Config::default();
        config.stop_bits = StopBits::STOP2;
        config.parity = Parity::ParityNone;
        config.data_bits = DataBits::DataBits8;
        config.baudrate = 250_000;

