        let de_pin = Output::new(
            de,
            embassy_stm32::gpio::Level::High,
            embassy_stm32::gpio::Speed::Low,
        );

        return Self {
            usart,
            de_pin,
            dir: DmxDirection::Output,
        };
    }

    async fn send_break(&amp;self) {
        self.usart.set_baudrate(110000).unwrap();
        self.usart.send_break();
        Timer::after_micros(150).await;
        self.usart.set_baudrate(250000).unwrap();
    }

    pub async fn send_dmx(&amp;mut self, buffer: &amp;[u8]) {
        match self.dir {
            DmxDirection::Input =&gt; {}
            DmxDirection::Output =&gt; {
                assert!(buffer.len() &lt;= 512);

                self.send_break().await;
                self.usart.blocking_write(&amp;[0xFF]).unwrap();
                self.usart.write(buffer).await.unwrap();
            }
        }
    }

    pub async fn read_dmx(&amp;mut self) {
        match self.dir {
            DmxDirection::Output =&gt; {}
            DmxDirection::Input =&gt; {
                let mut buffer: [u8; 513] = [0; 513];

                loop {
                    match self.usart.read(&amp;mut buffer).await {
                        Ok(n) =&gt; {
                            defmt::debug!(&quot;{}&quot;, buffer[0..513]);
                        }
                        Err(e) =&gt; {
                            defmt::debug!(&quot;{}, {}&quot;,e, buffer[0..513]);
                        }
                    }
                }
            }
        }
    }

    pub fn set_direction(&amp;mut self, dir: DmxDirection) {
        self.dir = dir;

        match self.dir {
            DmxDirection::Input =&gt; self.de_pin.set_low(),
            DmxDirection::Output =&gt; self.de_pin.set_high(),
        }
    }
}
