            println!(
                &quot;latencies for {} entries: push={}us, submit={}us&quot;,
                count,
                (time_pushed - time_start) / 1000,
                (time_submitted - time_pushed) / 1000
            );
        }

        let cqe = ring.completion().next();

        if cqe.is_none() {
            yield_now();
            continue;
        }        

        // ...handle cqe...

    }
</code></pre>
<p>full source code is here: <a href="https://github.com/eXistence/iouring_test/blob/main/src/main.rs" rel="nofollow noreferrer">https://github.com/eXistence/iouring_test/blob/main/src/main.rs</a></p>
<p>Log output looks like this:</p>
