static const GUID IID_IWaitCursorManager =
    { 0xfc992f1f, 0xdebb, 0x4596, { 0xb3, 0x55, 0x50, 0xc7, 0xa6, 0xdd, 0x12, 0x22 } };

// No-op IWaitCursorManager implementation
class NoOpWaitCursorManager : public IUnknown {
public:
    // IUnknown
    HRESULT STDMETHODCALLTYPE QueryInterface(REFIID riid, void** ppv) override {
        if (riid == IID_IUnknown || riid == IID_IWaitCursorManager) {
            *ppv = this;
            AddRef();
            return S_OK;
        }
        *ppv = nullptr;
        return E_NOINTERFACE;
    }

    ULONG STDMETHODCALLTYPE AddRef() override { return ++m_refCount; }
    ULONG STDMETHODCALLTYPE Release() override {
        ULONG count = --m_refCount;
        if (count == 0) delete this;
        return count;
    }

    // IWaitCursorManager (vtable order matters!)
    HRESULT STDMETHODCALLTYPE Start(int /*cursorId*/) { return S_OK; }
    HRESULT STDMETHODCALLTYPE Restore() { return S_OK; }
    HRESULT STDMETHODCALLTYPE Stop(int /*cursorId*/) { return S_OK; }

private:
    std::atomic&lt;ULONG&gt; m_refCount{1};
};

// IServiceProvider that returns NoOpWaitCursorManager
class WaitCursorSuppressor : public IServiceProvider {
public:
    WaitCursorSuppressor() : m_cursorManager(new NoOpWaitCursorManager()) {}
    ~WaitCursorSuppressor() { m_cursorManager-&gt;Release(); }

    // IUnknown
    HRESULT STDMETHODCALLTYPE QueryInterface(REFIID riid, void** ppv) override {
        if (riid == IID_IUnknown || riid == IID_IServiceProvider) {
            *ppv = this;
            AddRef();
            return S_OK;
        }
        *ppv = nullptr;
        return E_NOINTERFACE;
    }

    ULONG STDMETHODCALLTYPE AddRef() override { return ++m_refCount; }
    ULONG STDMETHODCALLTYPE Release() override {
        ULONG count = --m_refCount;
        if (count == 0) delete this;
        return count;
    }

    // IServiceProvider
    HRESULT STDMETHODCALLTYPE QueryService(REFGUID guidService, REFIID riid, void** ppv) override {
        if (guidService == IID_IWaitCursorManager &amp;&amp; riid == IID_IWaitCursorManager) {
            *ppv = m_cursorManager;
            m_cursorManager-&gt;AddRef();
            return S_OK;
        }
        *ppv = nullptr;
        return E_NOINTERFACE;
    }

private:
    std::atomic&lt;ULONG&gt; m_refCount{1};
    NoOpWaitCursorManager* m_cursorManager;
};

// Usage: call before QueryContextMenu
void SetupCursorSuppression(IContextMenu* contextMenu) {
    IObjectWithSite* site = nullptr;
    if (SUCCEEDED(contextMenu-&gt;QueryInterface(IID_IObjectWithSite, (void**)&amp;site))) {
        IServiceProvider* suppressor = new WaitCursorSuppressor();
        site-&gt;SetSite(suppressor);
        // SetSite takes ownership
        site-&gt;Release();
    }
}
