                ).unwrap();
            } else {
                write!(
                    handle,
                    &quot;\x1b_Gm={};{}\x1b\\&quot;,
                    m, chunk
                ).unwrap();
            }
        }

        handle.flush().unwrap();

        time += 0.1;
    }
}
