    /// ```rust
    /// use doctest_api_visibility::public_module::public_api;
    ///
    /// assert_eq!(public_api(), 2252025);
    /// ```
    pub fn public_api() -&gt; u64 {
        private_api() + 16
    }
}

#[cfg(doctest)]
