pub async fn fetch_trades_from_azure() -&gt; Result&lt;Vec&lt;TradeData&gt;, String&gt; {
    let start = std::time::Instant::now();
    println!(&quot;[LOG] [Azure] Starting fetch_trades_from_azure&quot;);

