Task: Implementing Arbitrary Precision Arithmetic in CubeCL for Infinite Zoom Fractals

 <h3>Context</h3>
<p>I'm implementing a Julia set fractal renderer using <a href="https://github.com/tracel-ai/cubecl" rel="nofollow noreferrer">CubeCL</a> (a Rust GPU compute framework). I want to achieve &quot;infinite zoom&quot; similar to deep Mandelbrot zoom videos, which requires arbitrary precision arithmetic that scales with zoom depth.</p>
<h3>Problem</h3>
<p>Standard <code>f64</code> precision (~15 decimal digits) limits zoom to about 10^15. Beyond this, precision loss causes pixelation. I need to implement multi-precision floating point directly in CubeCL shaders to extend this limit.</p>
<h3>What I've Tried</h3>
<pre class="lang-rust prettyprint-override"><code>use cubecl::prelude::*;
use minifb::{Key, Window, WindowOptions};

const W: usize = 800;
const H: usize = 600;

// ============================================================================
// SIMPLIFIED ARBITRARY PRECISION (using f64 array for extended precision)
// ============================================================================

#[derive(Clone, Debug)]
struct MultiFloat {
    // Value = parts[0] + parts[1] + parts[2] + parts[3]
    // Each part decreases in magnitude
    parts: [f64; 4],
}

impl MultiFloat {
    fn from_f64(val: f64) -&gt; Self {
        Self {
            parts: [val, 0.0, 0.0, 0.0],
        }
    }

    fn zero() -&gt; Self {
        Self {
            parts: [0.0, 0.0, 0.0, 0.0],
        }
    }

    fn to_f64(&amp;self) -&gt; f64 {
        self.parts[0] + self.parts[1] + self.parts[2] + self.parts[3]
    }

    // Two-sum algorithm for exact addition
    fn two_sum(a: f64, b: f64) -&gt; (f64, f64) {
        let s = a + b;
        let v = s - a;
        let e = (a - (s - v)) + (b - v);
        (s, e)
    }

    // Two-product algorithm
    fn two_prod(a: f64, b: f64) -&gt; (f64, f64) {
        let p = a * b;
        let e = a.mul_add(b, -p); // fma when available
        (p, e)
    }

    fn add(&amp;self, other: &amp;MultiFloat) -&gt; MultiFloat {
        let mut result = [0.0; 4];

        // Add all parts
        let (s0, e0) = Self::two_sum(self.parts[0], other.parts[0]);
        let (s1, e1) = Self::two_sum(self.parts[1], other.parts[1]);
        let (s2, e2) = Self::two_sum(self.parts[2], other.parts[2]);
        let (s3, e3) = Self::two_sum(self.parts[3], other.parts[3]);

        // Accumulate errors
        result[0] = s0;
        result[1] = s1 + e0;
        result[2] = s2 + e1;
        result[3] = s3 + e2 + e3;

        // Simple renormalization
        for _ in 0..2 {
            for i in (1..4).rev() {
                let (s, e) = Self::two_sum(result[i - 1], result[i]);
                result[i - 1] = s;
                result[i] = e;
            }
        }

        MultiFloat { parts: result }
    }

    fn mul(&amp;self, other: &amp;MultiFloat) -&gt; MultiFloat {
        // Simplified multiplication - compute most significant terms
        let (p0, e0) = Self::two_prod(self.parts[0], other.parts[0]);

        let p1 = self.parts[0] * other.parts[1] + self.parts[1] * other.parts[0] + e0;
        let p2 = self.parts[0] * other.parts[2]
            + self.parts[1] * other.parts[1]
            + self.parts[2] * other.parts[0];
        let p3 = self.parts[0] * other.parts[3]
            + self.parts[1] * other.parts[2]
            + self.parts[2] * other.parts[1]
            + self.parts[3] * other.parts[0];

        let mut result = MultiFloat {
            parts: [p0, p1, p2, p3],
        };

        // Renormalize
        for _ in 0..2 {
            for i in (1..4).rev() {
                let (s, e) = Self::two_sum(result.parts[i - 1], result.parts[i]);
                result.parts[i - 1] = s;
                result.parts[i] = e;
            }
        }

        result
    }

    fn sub(&amp;self, other: &amp;MultiFloat) -&gt; MultiFloat {
        let neg_other = MultiFloat {
            parts: [
                -other.parts[0],
                -other.parts[1],
                -other.parts[2],
                -other.parts[3],
            ],
        };
        self.add(&amp;neg_other)
    }

    fn scale(&amp;self, s: f64) -&gt; MultiFloat {
        let scalar = MultiFloat::from_f64(s);
        self.mul(&amp;scalar)
    }
}

// ============================================================================
// Julia Set Computer
// ============================================================================

fn compute_julia_pixel(
    cx: f64,
    cy: f64,
    center_x: &amp;MultiFloat,
    center_y: &amp;MultiFloat,
    zoom: f64,
    px: usize,
    py: usize,
    width: usize,
    height: usize,
    max_iter: u32,
) -&gt; u32 {
    let aspect = width as f64 / height as f64;

    // Map pixel to complex plane
    let nx = (px as f64 / width as f64 - 0.5) * 4.0 * aspect;
    let ny = (py as f64 / height as f64 - 0.5) * 4.0;

    // Scale by zoom and add to center
    let dx = MultiFloat::from_f64(nx / zoom);
    let dy = MultiFloat::from_f64(ny / zoom);

    let mut zx = center_x.add(&amp;dx);
    let mut zy = center_y.add(&amp;dy);

    let c_real = MultiFloat::from_f64(cx);
    let c_imag = MultiFloat::from_f64(cy);

    for iter in 0..max_iter {
        // Check escape: |z|^2 &gt; 4
        let zx_val = zx.to_f64();
        let zy_val = zy.to_f64();
        let mag_sq = zx_val * zx_val + zy_val * zy_val;

        if mag_sq &gt; 256.0 {
            return iter;
        }

        // z = z^2 + c
        // new_x = x^2 - y^2 + cx
        // new_y = 2*x*y + cy
        let zx_sq = zx.mul(&amp;zx);
        let zy_sq = zy.mul(&amp;zy);
        let zx_zy = zx.mul(&amp;zy);

        let new_zx = zx_sq.sub(&amp;zy_sq).add(&amp;c_real);
        let new_zy = zx_zy.add(&amp;zx_zy).add(&amp;c_imag);

        zx = new_zx;
        zy = new_zy;
    }

    max_iter
}

