    let idx = ABSOLUTE_POS;

    if idx &lt; width * height {
        let iter = iterations[idx];

        let mut r = 0.0f32;
        let mut g = 0.0f32;
        let mut b = 0.0f32;

        if iter &lt; max_iter {
            let smooth = iter as f64 / max_iter as f64;

            if palette == 0u32 {
                r = f64::powf(smooth, 0.4) as f32;
                g = (smooth * smooth) as f32;
                b = f64::sqrt(f64::max(0.0, 1.0 - smooth)) as f32;
            }
            if palette == 1u32 {
                let angle = smooth * 6.28318 * 4.0;
                r = (f64::sin(angle) * 0.5 + 0.5) as f32;
                g = (f64::sin(angle + 2.094) * 0.5 + 0.5) as f32;
                b = (f64::sin(angle + 4.189) * 0.5 + 0.5) as f32;
            }
            if palette == 2u32 {
                r = f64::powf(smooth, 0.3) as f32;
                g = f64::powf(smooth, 1.5) as f32;
                b = (smooth * smooth * smooth) as f32;
            }
            if palette == 3u32 {
                let t = smooth * 3.14159 * 2.0;
                r = (f64::abs(f64::sin(t * 3.0)) * 0.8 + 0.2) as f32;
                g = (f64::abs(f64::sin(t * 5.0 + 1.0)) * 0.8 + 0.2) as f32;
                b = (f64::abs(f64::cos(t * 7.0)) * 0.8 + 0.2) as f32;
            }
        }

        let out_idx = idx * 3u32;
        output[out_idx] = r;
        output[out_idx + 1u32] = g;
        output[out_idx + 2u32] = b;
    }
}

