    let session_arc = Arc::new(Mutex::new(session));
    let reader = session_arc.clone();
    std::thread::spawn(move || {
      let mut buf = [0u8; 1024];
      loop {
        // Holds the lock while performing a blocking read
        let n = { let mut g = reader.lock().unwrap(); match g.read(&amp;mut buf) { Ok(n) =&gt; n, Err(_) =&gt; 0 } };
        if n == 0 { let _ = app.emit(&quot;agent-output&quot;, &quot;[process terminated]\r\n&quot;.to_string()); break; }
        let out = String::from_utf8_lossy(&amp;buf[..n]).to_string();
        let _ = app.emit(&quot;agent-output&quot;, out);
      }
    });
    Ok(Self { session: session_arc })
  }

  pub fn send(&amp;mut self, data: &amp;str) {
    // Blocks if the read thread is holding the lock on a blocking read
    let mut guard = self.session.lock().unwrap();
    let _ = guard.send(data);
  }
}
