Task: Multithreaded Web Server from the Rust book, but implemented with shared memory instead of message passing

 <p>I'm following the Rust Book's chapter 20 to create a multithreaded web server. Everything went pretty smooth, the implementation they describe up until the end of <a href="https://doc.rust-lang.org/book/ch21-02-multithreaded.html" rel="nofollow noreferrer">this chapter</a> works as expected.</p>
<p>Here's the code for it, just so that you don't have to gather it from pieces:</p>
<pre class="lang-rust prettyprint-override"><code>// main.rs
use std::io::{BufRead, BufReader, Write};
use std::net::{TcpListener, TcpStream};
use std::time::Duration;
use std::{fs, thread};
use thr::ThreadPool;

fn main() {
    let listener = TcpListener::bind(&quot;127.0.0.1:7878&quot;).unwrap();
    let pool = ThreadPool::new(4);

    for stream in listener.incoming() {
        let stream = stream.unwrap();

        pool.execute(|| handle_connection(stream));
    }
}

fn handle_connection(mut stream: TcpStream) {
    let buff_reader = BufReader::new(&amp;stream);
    let request_line = buff_reader.lines().next().unwrap().unwrap();

    let (status_line, file_name) = match &amp;request_line[..] {
        &quot;GET / HTTP/1.1&quot; =&gt; (&quot;HTTP/1.1 200 OK&quot;, &quot;hello.html&quot;),
        &quot;GET /sleep HTTP/1.1&quot; =&gt; {
            thread::sleep(Duration::from_secs(5));
            (&quot;HTTP/1.1 200 OK&quot;, &quot;hello.html&quot;)
        }
        _ =&gt; (&quot;HTTP/1.1 404 NOT FOUND&quot;, &quot;404.html&quot;),
    };

    let html = fs::read_to_string(file_name).unwrap();

    let len = html.len();
    let resp = format!(&quot;{status_line}\r\nContent-Length: {len}\r\n\r\n{html}&quot;);

