<pre class="lang-rust prettyprint-override"><code>// lib.rs
use std::sync::{mpsc, Arc, Mutex};
use std::thread;
use std::thread::JoinHandle;

struct Worker {
    id: usize,
    handle: JoinHandle&lt;()&gt;,
}

impl Worker {
    fn new(id: usize, receiver: Arc&lt;Mutex&lt;mpsc::Receiver&lt;Job&gt;&gt;&gt;) -&gt; Worker {
        let handle = thread::spawn(move || {
            loop {
                let job = receiver.lock().unwrap().recv().unwrap();

                println!(&quot;Worker {id} got a job; executing.&quot;);

                job();
            }
        });
        Worker { id, handle }
    }
}

type Job = Box&lt;dyn FnOnce() + Send + 'static&gt;;

pub struct ThreadPool {
    workers: Vec&lt;Worker&gt;,
    sender: mpsc::Sender&lt;Job&gt;,
}

impl ThreadPool {
    /// Create a new ThreadPool.
    ///
    /// The size is the number of threads in the pool.
    ///
    /// # Panics
    ///
    /// The `new` function will panic if the size is zero.
    pub fn new(size: usize) -&gt; ThreadPool {
        assert!(size &gt; 0);

        let mut workers = Vec::with_capacity(size);
        let (sender, receiver) = mpsc::channel();

        let receiver = Arc::new(Mutex::new(receiver));

        for id in 0..size {
            let worker = Worker::new(id, Arc::clone(&amp;receiver));
            workers.push(worker);
        }

        ThreadPool { workers, sender }
    }

    pub fn build(size: usize) -&gt; Result&lt;ThreadPool, PoolCreationError&gt; {
        if size &gt; 0 {
            return Err(PoolCreationError);
        }
        Ok(ThreadPool::new(size))
    }

    pub fn execute&lt;F&gt;(&amp;self, f: F)
    where
        F: FnOnce() + Send + 'static,
    {
        self.sender.send(Box::new(f)).unwrap();
    }
}

pub struct PoolCreationError;
</code></pre>
<p>I have decided to rewrite it using the memory sharing mechanism instead of message passing, just for educational purposes. There are no changes in the <code>main.rs</code> file, and the updated <code>lib.rs</code> looks like this:</p>
<pre class="lang-rust prettyprint-override"><code>// lib.rs
use std::sync::{Arc, Mutex};
use std::thread;
use std::thread::JoinHandle;

struct Worker {
    id: usize,
    handle: JoinHandle&lt;()&gt;,
}

impl Worker {
    fn new(id: usize, queue: Arc&lt;Mutex&lt;Vec&lt;Job&gt;&gt;&gt;) -&gt; Worker {
        let handle = thread::spawn(move || {
            loop {
                let maybe_job = queue.lock().unwrap().pop();
                if let Some(job) = maybe_job {
                    job()
                }
            }
        });
        Worker { id, handle }
    }
}

type Job = Box&lt;dyn FnOnce() + Send + 'static&gt;;

pub struct ThreadPool {
    workers: Vec&lt;Worker&gt;,
    queue: Arc&lt;Mutex&lt;Vec&lt;Job&gt;&gt;&gt;,
}

impl ThreadPool {
    /// Create a new ThreadPool.
    ///
    /// The size is the number of threads in the pool.
    ///
    /// # Panics
    ///
    /// The `new` function will panic if the size is zero.
    pub fn new(size: usize) -&gt; ThreadPool {
        assert!(size &gt; 0);

        let mut workers = Vec::with_capacity(size);
        let queue = Arc::new(Mutex::new(Vec::with_capacity(size)));

        for id in 0..size {
            let worker = Worker::new(id, Arc::clone(&amp;queue));
            workers.push(worker);
        }

        ThreadPool { workers, queue }
    }

    pub fn build(size: usize) -&gt; Result&lt;ThreadPool, PoolCreationError&gt; {
        if size &gt; 0 {
            return Err(PoolCreationError);
        }
        Ok(ThreadPool::new(size))
    }

    pub fn execute&lt;F&gt;(&amp;self, f: F)
    where
        F: FnOnce() + Send + 'static,
    {
        self.queue.lock().unwrap().push(Box::new(f));
    }
}

pub struct PoolCreationError;

</code></pre>
<p>In short, instead of creating an <code>mpsc::channel</code> and passing a reference to the receiver to workers and holding the sender on the <code>ThreadPool</code> instance, I'm now holding in the <code>ThreadPool</code> instance a <code>queue</code>, which is a vector of jobs (<code>Arc&lt;Mutex&lt;Vec&lt;Job&gt;&gt;&gt;</code>) and passing to the workers a reference copy to the same queue.</p>
<p>Inside the worker, I'm making it <code>pop</code> the queue (which yields a job) and execute it.</p>
<p>Both versions compile and work. From what I can tell, they work identically (from the user's perspective, i.e. when making requests from a browser). The question is, <strong>is it really so</strong>? Am I not missing something? Are message passing and memory sharing really identical in this particular use case? What are other implications of my approach I don't see?</p>
<p>P.S. The only &quot;noticable&quot; distinction between the 2 versions for me is that the fans of my laptop seeminly start to spin faster for my memory sharing implementation. However, I'm not able to explain it looking at the system resources monitor, for example (which is also a bit unclear to me, why that happens).</p>


