<p>To do this, I am using divan(0.1.21) and rustc-nightly (1.90.0). Currently, I am benchmarking the standard library default HashMap implementation against a custom no-op hasher.</p>
<pre class="lang-rs prettyprint-override"><code>#[derive(Debug, Clone, Copy, PartialEq, Eq, Default)]
pub struct NoOpHasher(pub usize);

impl std::hash::Hasher for NoOpHasher {
    #[inline(always)]
    fn finish(&amp;self) -&gt; u64 {
        self.0 as u64
    }

    fn write(&amp;mut self, _: &amp;[u8]) {
        panic!(
            &quot;NoOpHasher::write should not be called: this is a no-op hasher custom built for u_ only&quot;
        )
    }

    #[inline(always)]
    fn write_u8(&amp;mut self, i: u8) {
        unsafe { std::ptr::write_volatile(&amp;mut self.0, i as usize) };
    }

    #[inline(always)]
    fn write_usize(&amp;mut self, i: usize) {
        unsafe { std::ptr::write_volatile(&amp;mut self.0, i) };
    }
}

impl std::hash::BuildHasher for NoOpHasher {
    type Hasher = NoOpHasher;

    fn build_hasher(&amp;self) -&gt; Self::Hasher {
        NoOpHasher(0)
    }
}
