Task: Implementation of a db multithread db batch reader in Rust

 <p>I'm writing a module in Rust that is supposed to pull data from a database in batches and provide an iterator for data consumption. I want the data to be pulled in a different thread and then be put into a queue. The second thread checks periodically the queue and if the length drops bellow 25% of the batch size, it reads a new batch. I have an implementation that works with a toy example (implementation below) and now I want to make it a template on the data it fetches.</p>
<p>The problem I'm facing is the collision of lifetime, self-referencing and multithreading.</p>
<p>I need to keep the db connection alive (I would prefer to keep the query <code>statement</code> also alive, but this is not as important). The below works because the connection and statement are defined in the thread function and are explicit. I'm trying to extract this logic out of the constructor so that it can be generalised to different types, but I cannot make it satisfy the lifetime requirements in a thread-safe way and at this point I'm out of my depth.</p>
<p>Any help is welcome.</p>
<p>My current implementation is below:</p>
<p><code>batch_reader.rs</code>:</p>
<pre><code>use rusqlite::ffi::ErrorCode;
use rusqlite::{Connection, Error, Result, Statement, params};
use serde::Serialize;
use std::any::TypeId;
use std::collections::VecDeque;
use std::marker::PhantomData;
use std::sync::atomic::{AtomicBool, Ordering};
use std::sync::{Arc, Condvar, Mutex};
use std::thread::{self, JoinHandle};
use std::time::Duration;

#[derive(Debug, Serialize)]
pub struct Person {
  id: i32,
  name: String,
  age: i32,
}

impl Default for Person {
  fn default() -&gt; Self {
    Person {
      id: 0,
      name: &quot;None&quot;.to_string(),
      age: 0,
    }
  }
}

struct DbReaderSharedState&lt;T&gt; {
  queue: VecDeque&lt;T&gt;,
  loader_done: bool,
}

pub struct BatchDbReader&lt;T&gt;
where
  T: Send + 'static,
{
  state: Arc&lt;Mutex&lt;DbReaderSharedState&lt;T&gt;&gt;&gt;,
  loader_cvar: Arc&lt;Condvar&gt;,
  consumer_cvar: Arc&lt;Condvar&gt;,
  shutdown: Arc&lt;AtomicBool&gt;,
  loader_thread: Option&lt;JoinHandle&lt;Result&lt;(), rusqlite::Error&gt;&gt;&gt;,
}

pub struct BatchDbIterator&lt;T&gt;
where
  T: Send + 'static,
{
  state: Arc&lt;Mutex&lt;DbReaderSharedState&lt;T&gt;&gt;&gt;,
  loader_cvar: Arc&lt;Condvar&gt;,
  consumer_cvar: Arc&lt;Condvar&gt;,
  shutdown: Arc&lt;AtomicBool&gt;,
  loader_thread: Option&lt;JoinHandle&lt;Result&lt;(), rusqlite::Error&gt;&gt;&gt;,
}

impl BatchDbReader&lt;Person&gt; {
  pub fn new(batch_size: usize) -&gt; rusqlite::Result&lt;Self&gt; {
    let load_threshold = (batch_size / 4).max(1);
    let state: Arc&lt;Mutex&lt;DbReaderSharedState&lt;Person&gt;&gt;&gt; = Arc::new(Mutex::new(DbReaderSharedState {
      queue: VecDeque::with_capacity(batch_size + load_threshold),
      loader_done: false,
    }));
    let loader_cvar = Arc::new(Condvar::new());
    let consumer_cvar = Arc::new(Condvar::new());
    let shutdown = Arc::new(AtomicBool::new(false));

    let thread_state: Arc&lt;Mutex&lt;DbReaderSharedState&lt;Person&gt;&gt;&gt; = state.clone();
    let thread_loader_cvar = loader_cvar.clone();
    let thread_consumer_cvar = consumer_cvar.clone();
    let thread_shutdown = shutdown.clone();
    let loader_thread = thread::spawn(move || -&gt; Result&lt;(), rusqlite::Error&gt; {
      let conn = Connection::open(&quot;test.sqlite&quot;)?;
      let mut statement = conn.prepare(&quot;SELECT id, name, age FROM people ORDER BY id LIMIT ? OFFSET ?&quot;).unwrap();
      let mut offset: usize = 0;
      while !thread_shutdown.load(Ordering::Relaxed) {
        let local_state = thread_state.lock().unwrap();
        if local_state.queue.len() &lt; load_threshold &amp;&amp; !local_state.loader_done {
          println!(&quot;batch loading: {} / {}&quot;, local_state.queue.len(), load_threshold);
          drop(local_state);
          let mut batch = statement.query_map(params![batch_size, offset], |row| {
            Ok(Person {
              id: row.get(0)?,
              name: row.get(1)?,
              age: row.get(2)?,
            })
          })?;

          let mut local_state = thread_state.lock().unwrap();
          if let Some(first_row) = batch.next() {
            local_state.queue.push_back(first_row?);
          } else {
            local_state.loader_done = true;
            thread_consumer_cvar.notify_one();
            break;
          }

          offset += batch_size;

          for p in batch {
            let person = p?;
            local_state.queue.push_back(person);
          }
          thread_consumer_cvar.notify_one();
        } else {
          let (_state, _result) = thread_loader_cvar.wait_timeout(local_state, Duration::from_millis(100)).unwrap();
        }
      }
      return Ok(());
    });

    Ok(Self {
      state,
      loader_cvar,
      consumer_cvar,
      shutdown,
      loader_thread: Some(loader_thread),
    })
  }

  pub fn into_iter(mut self) -&gt; BatchDbIterator&lt;Person&gt; {
    BatchDbIterator {
      state: self.state.clone(),
      loader_cvar: self.loader_cvar.clone(),
      consumer_cvar: self.consumer_cvar.clone(),
      shutdown: self.shutdown.clone(),
      loader_thread: self.loader_thread.take(),
    }
  }
}

impl&lt;T&gt; Iterator for BatchDbIterator&lt;T&gt;
where
  T: Send + 'static,
{
  type Item = T;

  fn next(&amp;mut self) -&gt; Option&lt;T&gt; {
    let mut state = self.state.lock().unwrap();

    loop {
      if let Some(item) = state.queue.pop_front() {
        return Some(item);
      }

      if state.loader_done {
        return None;
      }

      state = self.consumer_cvar.wait(state).unwrap();
    }
  }
}

impl&lt;T&gt; Drop for BatchDbIterator&lt;T&gt;
where
  T: Send + 'static,
{
  fn drop(&amp;mut self) {
    self.shutdown.store(true, Ordering::Relaxed);
    self.loader_cvar.notify_one();

    if let Some(thread) = self.loader_thread.take() {
      let _ = thread.join().unwrap();
    }
  }
}

impl&lt;T&gt; Drop for BatchDbReader&lt;T&gt;
where
  T: Send + 'static,
{
  fn drop(&amp;mut self) {
    if let Some(thread) = self.loader_thread.take() {
      self.shutdown.store(true, Ordering::Relaxed);
      self.loader_cvar.notify_one();
      let _ = thread.join().unwrap();
    }
  }
}
</code></pre>
