Task: How to use ADC on a STM32F303VC (Discovery Board) with Rust Embassy

 <p>I wrote a little embedded Rust project for my STM32F3 Discovery board. I attached a light sensor and continuously read the data from the sensor. I used the stm32f3xx-hal crate and the code looks like this:</p>
<pre class="lang-rust prettyprint-override"><code>#![no_main]
#![no_std]

extern crate panic_halt;

use cortex_m::asm;
use cortex_m_rt::entry;
use rtt_target::rtt_init_defmt;
use stm32f3xx_hal::{
    adc::{Adc, CommonAdc, config::Config},
    pac,
    prelude::*,
};

#[entry]
fn main() -&gt; ! {
    rtt_init_defmt!();
    defmt::info!(&quot;Starting light sensor application&quot;);

    let dp = pac::Peripherals::take().unwrap();

    let mut flash = dp.FLASH.constrain();
    let mut rcc = dp.RCC.constrain();

    let clocks = rcc.cfgr.use_hse(8.MHz()).freeze(&amp;mut flash.acr);
    let mut gpioa = dp.GPIOA.split(&amp;mut rcc.ahb);
    let mut light_pin = gpioa.pa0.into_analog(&amp;mut gpioa.moder, &amp;mut gpioa.pupdr);

    let mut adc = Adc::new(
        dp.ADC1,
        Config::default(),
        &amp;clocks,
        &amp;CommonAdc::new(dp.ADC1_2, &amp;clocks, &amp;mut rcc.ahb),
    );

    loop {
        let data: u16 = adc.read(&amp;mut light_pin).unwrap();
        defmt::info!(&quot;{}&quot;, data);

        // Wait 100ms for next conversion
        asm::delay(800_000);
    }
}
